import React from 'react';
import './Works.css';

const dummyGoods = Array.from({ length: 30 }, (_, i) => ({
  id: i + 1,
  title: `お気に入りグッズ${i + 1}`,
  image: 'https://via.placeholder.com/120x120?text=Goods',
  url: i % 2 === 0
    ? 'https://shop.asobistore.jp/category/10107/'
    : 'https://list.amiami.jp/top/search/list?s_originaltitle_id=36257&pagecnt=40&getcnt=0&pagehnt=2',
}));

function Favorites() {
  return (
    <div className="works-container">
      <h2>お気に入りの作品</h2>
      <div className="works-grid">
        {dummyGoods.map(good => (
          <a
            className="work-card"
            key={good.id}
            href={good.url}
            target="_blank"
            rel="noopener noreferrer"
          >
            <div className="work-image">
              <img src={good.image} alt={good.title} style={{ width: '80px', height: '80px', objectFit: 'cover', borderRadius: '8px' }} />
            </div>
            <div className="work-info">
              <h3 className="work-title">{good.title}</h3>
            </div>
          </a>
        ))}
      </div>
    </div>
  );
}

export default Favorites;
